    "startFrame": 24750,
    "durationSec": 2.986666666666667,
    "durationFrames": 90,
    "speaker": "ずんだもん",
    "text": "いい視点なのだ。業界の実験ではね。",
    "speakerColor": "#22c55e",
    "sceneId": 24,
    "sceneTitle": "AIの影響",
    "audioFile": "audio/proj_afbe778d/scene_24_01.wav"
